// Azure IoT Hub Device Provisioning with TPM 2.0
// Eliminates hardcoded credentials using hardware-backed security

#include <stdio.h>
#include <stdlib.h>
#include "azure_c_shared_utility/platform.h"
#include "azure_c_shared_utility/threadapi.h"
#include "iothub_device_client.h"
#include "iothub_client_options.h"
#include "iothubtransportmqtt.h"
#include "azure_prov_client/prov_device_client.h"
#include "azure_prov_client/prov_security_factory.h"
#include "azure_prov_client/prov_transport_mqtt_client.h"

// DPS Configuration (public values, NOT secrets)
#define DPS_GLOBAL_ENDPOINT "global.azure-devices-provisioning.net"
#define DPS_ID_SCOPE "0ne00XXXXXX"  // Your DPS ID Scope
#define REGISTRATION_ID "iot-device-tpm-001"  // Unique device registration ID

static bool g_registration_complete = false;

// Callback when device registration is complete
static void registration_status_callback(PROV_DEVICE_REG_STATUS reg_status, void* user_context)
{
    if (reg_status == PROV_DEVICE_REG_STATUS_CONNECTED)
    {
        printf("Device connected to DPS\n");
    }
    else if (reg_status == PROV_DEVICE_REG_STATUS_REGISTERING)
    {
        printf("Device registering with DPS using TPM...\n");
    }
    else if (reg_status == PROV_DEVICE_REG_STATUS_ASSIGNING)
    {
        printf("DPS assigning device to IoT Hub...\n");
    }
}

// Callback when device is assigned to IoT Hub
static void register_device_callback(PROV_DEVICE_RESULT register_result, const char* iothub_uri, 
                                     const char* device_id, void* user_context)
{
    if (register_result == PROV_DEVICE_RESULT_OK)
    {
        printf("Registration successful!\n");
        printf("IoT Hub: %s\n", iothub_uri);
        printf("Device ID: %s\n", device_id);
        g_registration_complete = true;
    }
    else
    {
        printf("Registration failed with error: %d\n", register_result);
        g_registration_complete = true;
    }
}

int main(void)
{
    PROV_DEVICE_HANDLE prov_device_handle;
    PROV_DEVICE_RESULT prov_result;

    // Initialize platform
    if (platform_init() != 0)
    {
        printf("Failed to initialize platform\n");
        return 1;
    }

    // Initialize security with TPM (NO hardcoded credentials!)
    if (prov_dev_security_init(SECURE_DEVICE_TYPE_TPM) != 0)
    {
        printf("Failed to initialize TPM security\n");
        platform_deinit();
        return 1;
    }

    printf("Initializing device provisioning with TPM 2.0...\n");

    // Create provisioning client using TPM authentication
    prov_device_handle = Prov_Device_Create(
        DPS_GLOBAL_ENDPOINT,
        DPS_ID_SCOPE,
        Prov_Device_MQTT_Protocol  // Use MQTT over TLS 1.2
    );

    if (prov_device_handle == NULL)
    {
        printf("Failed to create provisioning client\n");
        prov_dev_security_deinit();
        platform_deinit();
        return 1;
    }

    // Set registration ID (derived from TPM endorsement key)
    Prov_Device_Set_Option(prov_device_handle, PROV_REGISTRATION_ID, REGISTRATION_ID);

    // Enable detailed logging for debugging
    bool trace_on = true;
    Prov_Device_Set_Option(prov_device_handle, PROV_OPTION_LOG_TRACE, &trace_on);

    // Register device with DPS using TPM-based authentication
    printf("Registering device with Azure DPS using TPM credentials...\n");
    prov_result = Prov_Device_Register_Device(
        prov_device_handle,
        register_device_callback,
        NULL,
        registration_status_callback,
        NULL
    );

    if (prov_result != PROV_DEVICE_RESULT_OK)
    {
        printf("Failed to register device: %d\n", prov_result);
        Prov_Device_Destroy(prov_device_handle);
        prov_dev_security_deinit();
        platform_deinit();
        return 1;
    }

    // Wait for registration to complete
    while (!g_registration_complete)
    {
        ThreadAPI_Sleep(100);
    }

    printf("Device successfully provisioned with TPM-backed credentials!\n");

    // Clean up
    Prov_Device_Destroy(prov_device_handle);
    prov_dev_security_deinit();
    platform_deinit();

    return 0;
}

/*
 * SECURITY IMPLEMENTATION NOTES:
 * 
 * 1. TPM 2.0 Security:
 *    - Endorsement Key (EK) is burned into TPM at manufacturing
 *    - Storage Root Key (SRK) never leaves TPM
 *    - Device identity derived from TPM, not hardcoded
 * 
 * 2. Zero-Touch Provisioning:
 *    - Device auto-enrolls with DPS on first boot
 *    - No manual credential injection required
 *    - Supports fleet provisioning at scale
 * 
 * 3. Hardware Root of Trust:
 *    - Private keys stored in TPM, not filesystem
 *    - TPM prevents key extraction via firmware analysis
 *    - Resistant to UART/JTAG debugging attacks
 * 
 * 4. Certificate Rotation:
 *    - DPS automatically handles certificate renewal
 *    - No device firmware update required for re-provisioning
 * 
 * 5. Compliance:
 *    - Meets NIST 800-53 IA-5(1)(a) unique credential requirement
 *    - Aligns with IEC 62443-4-2 CR 1.5 password management
 */

// ESP32 IoT Device with ATECC608A Secure Element
// Eliminates extractable credentials via hardware key isolation

#include <stdio.h>
#include "esp_log.h"
#include "cryptoauthlib.h"
#include "atca_basic.h"
#include "mbedtls/x509_crt.h"
#include "mbedtls/pk.h"
#include "esp_tls.h"

static const char *TAG = "SECURE_IOT";

// ATECC608A I2C Configuration
ATCAIfaceCfg cfg_ateccx08a_i2c = {
    .iface_type = ATCA_I2C_IFACE,
    .devtype = ATECC608,
    .atcai2c.slave_address = 0xC0,
    .atcai2c.bus = 1,
    .atcai2c.baud = 400000,
    .wake_delay = 1500,
    .rx_retries = 20
};

/**
 * Initialize ATECC608A secure element
 * Private key is generated inside secure element and NEVER leaves chip
 */
esp_err_t init_secure_element(void)
{
    ATCA_STATUS status;

    ESP_LOGI(TAG, "Initializing ATECC608A Secure Element...");

    // Initialize cryptoauthlib
    status = atcab_init(&cfg_ateccx08a_i2c);
    if (status != ATCA_SUCCESS)
    {
        ESP_LOGE(TAG, "Failed to initialize ATECC608A: 0x%02x", status);
        return ESP_FAIL;
    }

    // Read device serial number (public information)
    uint8_t serial_number[9];
    status = atcab_read_serial_number(serial_number);
    if (status != ATCA_SUCCESS)
    {
        ESP_LOGE(TAG, "Failed to read serial number: 0x%02x", status);
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "Secure Element Serial: %02X%02X%02X%02X%02X%02X%02X%02X%02X",
             serial_number[0], serial_number[1], serial_number[2],
             serial_number[3], serial_number[4], serial_number[5],
             serial_number[6], serial_number[7], serial_number[8]);

    return ESP_OK;
}

/**
 * Generate ECC P-256 key pair in secure element
 * Private key NEVER exposed to ESP32 main processor
 */
esp_err_t generate_device_key_pair(uint16_t key_slot)
{
    ATCA_STATUS status;
    uint8_t public_key[64];  // ECC P-256 public key (can be shared)

    ESP_LOGI(TAG, "Generating ECC P-256 key pair in Secure Element slot %d...", key_slot);

    // Generate private key inside secure element (non-extractable)
    status = atcab_genkey(key_slot, public_key);
    if (status != ATCA_SUCCESS)
    {
        ESP_LOGE(TAG, "Failed to generate key pair: 0x%02x", status);
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "Key pair generated successfully!");
    ESP_LOGI(TAG, "Public Key (X): %02X%02X%02X...%02X%02X%02X",
             public_key[0], public_key[1], public_key[2],
             public_key[61], public_key[62], public_key[63]);

    // CRITICAL: Private key is locked in secure element
    // Cannot be read via UART, JTAG, or firmware extraction

    return ESP_OK;
}

/**
 * Sign data using private key in secure element
 * Private key never leaves secure element chip
 */
esp_err_t sign_with_secure_element(uint16_t key_slot, const uint8_t *message, 
                                    size_t message_len, uint8_t *signature)
{
    ATCA_STATUS status;
    uint8_t digest[32];  // SHA-256 digest

    // Compute SHA-256 digest of message
    status = atcab_hw_sha2_256(message, message_len, digest);
    if (status != ATCA_SUCCESS)
    {
        ESP_LOGE(TAG, "Failed to compute digest: 0x%02x", status);
        return ESP_FAIL;
    }

    // Sign digest using private key in secure element
    // Private key NEVER exposed during this operation
    status = atcab_sign(key_slot, digest, signature);
    if (status != ATCA_SUCCESS)
    {
        ESP_LOGE(TAG, "Failed to sign data: 0x%02x", status);
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "Data signed successfully with secure element");
    return ESP_OK;
}

/**
 * Establish TLS connection to IoT platform using secure element credentials
 */
esp_err_t connect_to_iot_platform(void)
{
    const char *iot_endpoint = "a3qjexample-ats.iot.us-east-1.amazonaws.com";
    const char *device_cert_pem = "-----BEGIN CERTIFICATE-----\n...";

    esp_tls_cfg_t tls_cfg = {
        .cacert_buf = (const unsigned char *)device_cert_pem,
        .cacert_bytes = strlen(device_cert_pem) + 1,
        .use_secure_element = true,  // Use ATECC608A for TLS
        .ds_data = NULL  // Secure element handles key operations
    };

    ESP_LOGI(TAG, "Connecting to IoT platform with secure element authentication...");

    esp_tls_t *tls = esp_tls_init();
    if (esp_tls_conn_new_sync(iot_endpoint, strlen(iot_endpoint), 8883, &tls_cfg, tls) == 1)
    {
        ESP_LOGI(TAG, "TLS connection established using secure element!");
        esp_tls_conn_destroy(tls);
        return ESP_OK;
    }
    else
    {
        ESP_LOGE(TAG, "TLS connection failed");
        esp_tls_conn_destroy(tls);
        return ESP_FAIL;
    }
}

void app_main(void)
{
    // Initialize secure element
    if (init_secure_element() != ESP_OK)
    {
        ESP_LOGE(TAG, "Secure element initialization failed. Halting.");
        return;
    }

    // Generate key pair (do this ONCE during manufacturing)
    // In production, key generation happens in secure factory environment
    const uint16_t DEVICE_KEY_SLOT = 0;
    if (generate_device_key_pair(DEVICE_KEY_SLOT) != ESP_OK)
    {
        ESP_LOGE(TAG, "Key generation failed. Halting.");
        return;
    }

    // Test signing operation
    const char *test_message = "Hello from secure IoT device";
    uint8_t signature[64];
    if (sign_with_secure_element(DEVICE_KEY_SLOT, 
                                  (const uint8_t *)test_message, 
                                  strlen(test_message), 
                                  signature) == ESP_OK)
    {
        ESP_LOGI(TAG, "Message signed successfully!");
    }

    // Connect to IoT platform
    connect_to_iot_platform();

    ESP_LOGI(TAG, "Device running with hardware-protected credentials!");
}

/*
 * SECURITY ADVANTAGES:
 * 
 * 1. Hardware Key Isolation:
 *    - Private key generated and stored in ATECC608A
 *    - ESP32 main processor NEVER has access to private key
 *    - Resistant to firmware dumping and memory analysis
 * 
 * 2. Anti-Tampering:
 *    - Secure element has internal tamper detection
 *    - Keys are destroyed if physical attack detected
 *    - Encrypted key storage within secure element
 * 
 * 3. Side-Channel Resistance:
 *    - Hardware countermeasures against power analysis
 *    - Constant-time cryptographic operations
 *    - Randomized signing to prevent timing attacks
 * 
 * 4. Cost-Effective:
 *    - ATECC608A costs ~$0.50 per unit in volume
 *    - No TPM required for basic IoT security
 *    - Compatible with ESP32, STM32, Arduino
 */
